return [{
  json: {
    shipmentId: 'SH-KL-2026-001',
    manifestType: 'ocean_bill_of_lading',
    pdfUrl: 'https://example.com/manifest.pdf',
    vessel: 'MAERSK EDINBURGH',
    voyage: '267E',
    containerNumber: 'MSKU1234567',
    arrivalPort: 'Port of Los Angeles',
    eta: '2026-03-05',
    shipper: {
      name: 'Shanghai Electronics Co.',
      address: '123 Industrial Rd, Shanghai, China'
    },
    consignee: {
      name: 'TechCorp USA',
      address: '456 Commerce St, Los Angeles, CA 90021',
      taxId: '12-3456789'
    },
    cargo: [
      {
        description: 'Electronic Components - Circuit Boards',
        hsCode: '8534.00.00',
        quantity: 5000,
        unit: 'PCS',
        value: 125000,
        currency: 'USD',
        weight: 2500
      },
      {
        description: 'Semiconductor Chips',
        hsCode: '8542.31.00',
        quantity: 10000,
        unit: 'PCS',
        value: 250000,
        currency: 'USD',
        weight: 500
      }
    ],
    totalValue: 375000,
    totalWeight: 3000,
    countryOfOrigin: 'CN'
  }
}];

const manifest = $input.first().json;
const redFlags = [];
let riskScore = 0;

// Check 1: High-value shipment
if (manifest.totalValue > 250000) {
  redFlags.push('High value shipment ($' + manifest.totalValue + ')');
  riskScore += 30;
}

// Check 2: Electronics from China
if (manifest.countryOfOrigin === 'CN' && manifest.cargo.some(c => c.description.toLowerCase().includes('electronic'))) {
  redFlags.push('Electronics from China - requires HTSUS verification');
  riskScore += 20;
}

// Check 3: Missing or incomplete data
if (!manifest.consignee.taxId) {
  redFlags.push('Missing consignee Tax ID');
  riskScore += 25;
}

// Check 4: Suspicious weight/value ratio
const valuePerKg = manifest.totalValue / manifest.totalWeight;
if (valuePerKg > 100) {
  redFlags.push('High value-to-weight ratio ($' + valuePerKg.toFixed(2) + '/kg)');
  riskScore += 15;
}

// Check 5: Semiconductor chips (controlled items)
if (manifest.cargo.some(c => c.description.toLowerCase().includes('semiconductor') || c.hsCode.startsWith('8542'))) {
  redFlags.push('Semiconductor chips - possible EAR restrictions');
  riskScore += 35;
}

// Check 6: First-time shipper (mock check)
const knownShippers = ['Shanghai Electronics Co.', 'Guangzhou Traders Ltd.'];
if (!knownShippers.includes(manifest.shipper.name)) {
  redFlags.push('New/unverified shipper');
  riskScore += 10;
}

return [{
  json: {
    ...manifest,
    extractedData: {
      entryType: 'Consumption',
      portOfEntry: manifest.arrivalPort,
      importerOfRecord: manifest.consignee,
      suretyBond: 'SINGLE_TRANSACTION'
    },
    redFlags,
    riskScore,
    requiresHumanReview: riskScore >= 50 || redFlags.length >= 3,
    autoProcessEligible: riskScore < 30 && redFlags.length === 0
  }
}];

